from __future__ import annotations
import uuid
from fastapi import FastAPI, HTTPException, Response
from pydantic import BaseModel
from typing import Optional

app = FastAPI(title="Agent Run API", version="1.0.0")

# In-memory store (replace with DB in production)
runs: dict[str, dict] = {}


class CreateRunRequest(BaseModel):
    model: str
    system_prompt: str
    user_message: str
    max_steps: int = 10


class PatchRunRequest(BaseModel):
    status: Optional[str] = None   # "cancelled"


# --- Collection endpoints ---

@app.get("/v1/runs", summary="List all runs")
def list_runs(status: Optional[str] = None) -> list[dict]:
    items = list(runs.values())
    if status:
        items = [r for r in items if r["status"] == status]
    return items


@app.post("/v1/runs", status_code=201, summary="Create a new run")
def create_run(req: CreateRunRequest, response: Response) -> dict:
    run_id = str(uuid.uuid4())
    run = {
        "id": run_id,
        "model": req.model,
        "system_prompt": req.system_prompt,
        "user_message": req.user_message,
        "max_steps": req.max_steps,
        "status": "queued",
        "steps": [],
    }
    runs[run_id] = run
    response.headers["Location"] = f"/v1/runs/{run_id}"  # RFC 7231
    return run


# --- Instance endpoints ---

@app.get("/v1/runs/{run_id}", summary="Get a specific run")
def get_run(run_id: str) -> dict:
    run = runs.get(run_id)
    if not run:
        raise HTTPException(status_code=404, detail={"code": "run_not_found",
                                                      "message": f"Run {run_id!r} not found"})
    return run


@app.patch("/v1/runs/{run_id}", summary="Partially update a run")
def patch_run(run_id: str, patch: PatchRunRequest) -> dict:
    run = runs.get(run_id)
    if not run:
        raise HTTPException(status_code=404, detail={"code": "run_not_found",
                                                      "message": f"Run {run_id!r} not found"})
    if patch.status is not None:
        allowed_transitions = {"queued": {"cancelled"}, "running": {"cancelled"}}
        current = run["status"]
        if patch.status not in allowed_transitions.get(current, set()):
            raise HTTPException(status_code=409,
                                detail={"code": "invalid_transition",
                                        "message": f"Cannot transition {current!r} → {patch.status!r}"})
        run["status"] = patch.status
    return run


@app.delete("/v1/runs/{run_id}", status_code=204, summary="Delete a run")
def delete_run(run_id: str) -> None:
    if run_id not in runs:
        raise HTTPException(status_code=404, detail={"code": "run_not_found",
                                                      "message": f"Run {run_id!r} not found"})
    del runs[run_id]


# --- Action sub-resource ---

@app.post("/v1/runs/{run_id}/cancel", summary="Cancel a run (idempotent action)")
def cancel_run(run_id: str) -> dict:
    run = runs.get(run_id)
    if not run:
        raise HTTPException(status_code=404, detail={"code": "run_not_found",
                                                      "message": f"Run {run_id!r} not found"})
    if run["status"] == "cancelled":
        return run  # already cancelled — idempotent, safe to retry
    if run["status"] == "completed":
        raise HTTPException(status_code=409, detail={"code": "already_completed",
                                                      "message": "Cannot cancel a completed run"})
    run["status"] = "cancelled"
    return run
